const favArtists = new Set();
for (const item of $input.all()) {
  if (item.json.name) {
    favArtists.add(item.json.name.toLowerCase());
  }
}

const drops = [];
const dedup = new Set();

for (const item of $input.all()) {
  const desc = item.json.description || item.json.title || '';
  const clean = desc.replace(/<[^>]+>/g, '\n');
  for (let line of clean.split('\n')) {
    line = line.trim();
    if (line.startsWith('•') || line.startsWith('-') || line.startsWith('—')) {
      const cleaned = line.replace(/^[•—\-*\s]+/, '');
      if (cleaned.includes('—') || cleaned.includes('-')) {
        const parts = cleaned.split(/\s+[—\-]\s+/);
        if (parts.length >= 2) {
          const art = parts[0].trim();
          const trk = parts[1].replace(/[«»"]/g, '').trim();
          if (art.length > 1 && trk.length > 1) {
            const key = `${art.toLowerCase()}_${trk.toLowerCase()}`;
            if (!dedup.has(key)) {
              dedup.add(key);
              const searchQ = encodeURIComponent(`${art} ${trk}`);
              drops.push({
                artist: art,
                title: trk,
                url: `https://open.spotify.com/search/${searchQ}`
              });
            }
          }
        }
      }
    }
  }
}

const tasteList = [];
const generalList = [];

for (const drop of drops) {
  const artLower = drop.artist.toLowerCase();
  let isFav = false;
  for (const fav of favArtists) {
    if (fav.includes(artLower) || artLower.includes(fav)) {
      isFav = true;
      break;
    }
  }
  if (isFav) tasteList.push(drop);
  else generalList.push(drop);
}

let msg = '🔥 *ПЯТНИЧНЫЙ МУЗЫКАЛЬНЫЙ РАДАР РЕЛИЗОВ* 🔥\n\n';
if (tasteList.length > 0) {
  msg += '🎧 *Твои любимые артисты*\n\n';
  for (const item of tasteList) {
    msg += `• [${item.artist} — ${item.title}](${item.url})\n`;
  }
  msg += '\n---\n\n';
}

if (generalList.length > 0) {
  msg += '⚡️ *Горячие новинки недели (РФ и Запад)*\n\n';
  for (const item of generalList.slice(0, 25)) {
    msg += `• [${item.artist} — ${item.title}](${item.url})\n`;
  }
  msg += '\n---\n\n';
}
msg += 'Нажмите на любой релиз, чтобы открыть его в Spotify! 🎧✨';

return [{ json: { message: msg } }];
